function longestConsecutive(nums) {
  const s = new Set(nums);
  let best = 0;
  for (let i = 0; i < nums.length; i++) {
    const x = nums[i];
    if (!s.has(x - 1)) {
      let len = 1;
      while (s.has(x + len)) len++;
      if (len > best) best = len;
    }
  }
  return best;
}
